package org.example

//TIP 코드를 <b>실행</b>하려면 <shortcut actionId="Run"/>을(를) 누르거나
// 에디터 여백에 있는 <icon src="AllIcons.Actions.Execute"/> 아이콘을 클릭하세요.
fun main() {
    val name = "Kotlin"
    //TIP 캐럿을 강조 표시된 텍스트에 놓고 <shortcut actionId="ShowIntentionActions"/>을(를) 누르면
    // IntelliJ IDEA이(가) 수정을 제안하는 것을 확인할 수 있습니다.
    println("Hello, " + name + "!")

    for (i in 1..5) {
        //TIP <shortcut actionId="Debug"/>을(를) 눌러 코드 디버그를 시작하세요. 1개의 <icon src="AllIcons.Debugger.Db_set_breakpoint"/> 중단점을 설정해 드렸습니다
        // 언제든 <shortcut actionId="ToggleLineBreakpoint"/>을(를) 눌러 중단점을 더 추가할 수 있습니다.
        println("i = $i")
    }
}

package org.example
import javafx.application.Application import javafx.scene.Scene import javafx.scene.control.Alert import javafx.scene.input.MouseButton import javafx.scene.input.MouseEvent import javafx.scene.layout.StackPane import javafx.scene.paint.Color import javafx.scene.shape.Rectangle import javafx.stage.Stage
class Main : Application() { override fun start(primaryStage: Stage) { val rectangle = Rectangle(200.0, 200.0, Color.BLUE) rectangle.setOnMouseClicked { event: MouseEvent -> if (event.button == MouseButton.SECONDARY) { // 우클릭 감지 val alert = Alert(Alert.AlertType.INFORMATION) alert.title = "우클릭 감지" alert.headerText = null alert.contentText = "상자를 우클릭했습니다!" alert.showAndWait() } }
val root = StackPane() root.children.add(rectangle)
val scene = Scene(root, 400.0, 400.0)
primaryStage.title = "Lucky Box" primaryStage.scene = scene primaryStage.show() } }
fun main() { Application.launch(Main::class.java) }

